import { Button, Content, ContentVariants } from '@patternfly/react-core';
import { CloseIcon } from '@patternfly/react-icons';
import React from 'react';
import Modal from 'react-modal';
import { useTheme } from '../../utils/theme-hook';
import './modal.css';

export interface CustomModalProps {
  title: string;
  description?: JSX.Element;
  footer?: JSX.Element;
  onClose?: () => void;
  isOpen: boolean;
  scrollable?: boolean;
  id?: string;
}

const CustomModal: React.FC<CustomModalProps> = ({
  id,
  scrollable = true,
  isOpen,
  onClose,
  title,
  description,
  children,
  footer
}) => {
  const isDarkTheme = useTheme();

  return isOpen ? (
    <Modal
      data-test={id}
      id={id}
      isOpen={isOpen}
      className={'modal-dialog'}
      ariaHideApp={false}
      onRequestClose={() => (onClose ? onClose() : console.error('modal called onClose but is undefined'))}
      overlayClassName="co-overlay"
    >
      <div className={`modal-content modal-content--no-inner-scroll ${isDarkTheme ? 'dark' : 'light'}`}>
        <div data-test={`${id}-header`} className="modal-header">
          <Content component={ContentVariants.h1}>
            {title}
            {onClose && (
              <Button
                data-test={`${id}-close-button`}
                className={'co-close-button co-close-button--float-right'}
                onClick={e => {
                  e.stopPropagation();
                  onClose();
                }}
                variant="plain"
                icon={<CloseIcon />}
              />
            )}
          </Content>
          {description && <div className="modal-description">{description}</div>}
        </div>
        {children && (
          <div data-test={`${id}-body`} className={`${'modal-body'} ${scrollable ? 'overflow-visible' : 'overflow-visible'}`}>
            {children}
          </div>
        )}
        {footer && (
          <div data-test={`${id}-footer`} className="modal-footer">
            {footer}
          </div>
        )}
      </div>
    </Modal>
  ) : (
    <></>
  );
};

export default CustomModal;

